# Python 3.11+
"""The room-selection SEAM (Strategy).

When several rooms are free for the requested slot, the booker expresses a
PREFERENCE for which one to take. That preference is exactly the policy the
product keeps extending. Each strategy receives the already-filtered candidate
rooms (free for the slot, big enough) and picks one — or None if the list is empty.
"""

from abc import ABC, abstractmethod

from models import Room


class RoomSelectionStrategy(ABC):
    @abstractmethod
    def select(self, rooms: list[Room]) -> Room | None:
        """Pick the best room for this preference, or None if there are none."""


class SmallestSufficientStrategy(RoomSelectionStrategy):
    """Least wasted capacity: the smallest room that still fits — don't put a
    2-person sync in a 50-seat auditorium."""

    def select(self, rooms: list[Room]) -> Room | None:
        if not rooms:
            return None
        return min(rooms, key=lambda r: (r.capacity, r.floor, r.id))


class LowestFloorStrategy(RoomSelectionStrategy):
    """Nearest/most accessible: prefer the lowest floor."""

    def select(self, rooms: list[Room]) -> Room | None:
        if not rooms:
            return None
        return min(rooms, key=lambda r: (r.floor, r.capacity, r.id))


class LargestRoomStrategy(RoomSelectionStrategy):
    """Most spare capacity: prefer the biggest room (room to grow the meeting)."""

    def select(self, rooms: list[Room]) -> Room | None:
        if not rooms:
            return None
        return max(rooms, key=lambda r: (r.capacity, -r.floor, r.id))
